import React, { createContext, useState, useContext, useEffect } from 'react';
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const UserContext = createContext();

export function UserProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [token, setToken] = useState(null);

  const api = axios.create({
    baseURL: API_BASE,
    headers: {
      'Content-Type': 'application/json'
    }
  });

  // Add token to all requests
  api.interceptors.request.use(config => {
    const t = localStorage.getItem('pv_token');
    if (t) {
      config.headers.Authorization = `Bearer ${t}`;
    }
    return config;
  });

  // Check if user is logged in on mount
  useEffect(() => {
    const t = localStorage.getItem('pv_token');
    if (t) {
      setToken(t);
      fetchCurrentUser(t);
    } else {
      setLoading(false);
    }
  }, []);

  const fetchCurrentUser = async (authToken) => {
    try {
      const config = { headers: { Authorization: `Bearer ${authToken}` } };
      const res = await axios.get(`${API_BASE}/users/me`, config);
      setUser(res.data.user);
    } catch (error) {
      localStorage.removeItem('pv_token');
      setToken(null);
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  const register = async (name, email, password) => {
    try {
      const res = await api.post('/users/register', { name, email, password });
      localStorage.setItem('pv_token', res.data.token);
      setToken(res.data.token);
      setUser(res.data.user);
      return res.data;
    } catch (error) {
      throw error.response?.data?.error || error.message;
    }
  };

  const login = async (email, password) => {
    try {
      const res = await api.post('/users/login', { email, password });
      localStorage.setItem('pv_token', res.data.token);
      setToken(res.data.token);
      setUser(res.data.user);
      return res.data;
    } catch (error) {
      throw error.response?.data?.error || error.message;
    }
  };

  const logout = () => {
    localStorage.removeItem('pv_token');
    setToken(null);
    setUser(null);
  };

  const incrementPromptUsage = async () => {
    try {
      const res = await api.post('/users/increment-usage');
      if (res.data.canAccess) {
        setUser(prev => ({
          ...prev,
          promptsUsed: res.data.promptsUsed
        }));
        return { success: true, data: res.data };
      } else {
        return { success: false, error: res.data.error };
      }
    } catch (error) {
      return { 
        success: false, 
        error: error.response?.data?.error || error.message 
      };
    }
  };

  const purchaseSubscription = async (planId) => {
    try {
      const res = await api.post('/subscription/purchase', { planId });
      setUser(prev => ({
        ...prev,
        subscription: res.data.subscription,
        promptsLimit: res.data.promptsLimit
      }));
      return { success: true, data: res.data };
    } catch (error) {
      throw error.response?.data?.error || error.message;
    }
  };

  const cancelSubscription = async () => {
    try {
      const res = await api.post('/subscription/cancel');
      setUser(prev => ({
        ...prev,
        subscription: res.data.subscription
      }));
      return { success: true, data: res.data };
    } catch (error) {
      throw error.response?.data?.error || error.message;
    }
  };

  const getSubscriptionStatus = async () => {
    try {
      const res = await api.get('/subscription/status');
      return res.data;
    } catch (error) {
      throw error.response?.data?.error || error.message;
    }
  };

  return (
    <UserContext.Provider value={{
      user,
      loading,
      token,
      login,
      register,
      logout,
      incrementPromptUsage,
      purchaseSubscription,
      cancelSubscription,
      getSubscriptionStatus,
      api
    }}>
      {children}
    </UserContext.Provider>
  );
}

export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) {
    throw new Error('useUser must be used within UserProvider');
  }
  return context;
};
